final class InMemoryBankDataStore {
    private final Object lock = new Object();

    private final HashMap<String, Account> accounts = new HashMap<>();
    private final HashMap<String, Money> balances = new HashMap<>();
    private final ArrayList<Transaction> transactions = new ArrayList<>();

    InMemoryBankDataStore() {
        Account a1 = new Account("A-1001", "Everyday Checking", "USD");
        Account a2 = new Account("A-2001", "Savings", "USD");
        accounts.put(a1.accountId, a1);
        accounts.put(a2.accountId, a2);
        balances.put(a1.accountId, Money.of("1250.00", "USD"));
        balances.put(a2.accountId, Money.of("5000.00", "USD"));
    }

    @NonNull
    List<Account> listAccounts() {
        synchronized (lock) {
            return new ArrayList<>(accounts.values());
        }
    }

    Account getAccount(String accountId) {
        synchronized (lock) {
            return accounts.get(accountId);
        }
    }

    Money getBalance(String accountId) {
        synchronized (lock) {
            return balances.get(accountId);
        }
    }

    void setBalance(String accountId, Money newBalance) {
        synchronized (lock) {
            balances.put(accountId, newBalance);
        }
    }

    void addTransaction(Transaction tx) {
        synchronized (lock) {
            transactions.add(tx);
        }
    }

    @NonNull
    List<Transaction> listTransactions() {
        synchronized (lock) {
            return Collections.unmodifiableList(new ArrayList<>(transactions));
        }
    }

    Object lock() {
        return lock;
    }
}

