package com.example.bankapp;

import androidx.annotation.NonNull;

import java.math.BigDecimal;
import java.util.Currency;
import java.util.UUID;

public final class TransactionProcessor {
    public static final class Result {
        public final boolean success;
        public final String message;
        public final Transaction transaction;

        Result(boolean success, String message, Transaction transaction) {
            this.success = success;
            this.message = message;
            this.transaction = transaction;
        }

        public static Result ok(Transaction tx) {
            return new Result(true, "OK", tx);
        }

        public static Result fail(String message) {
            return new Result(false, message, null);
        }
    }

    private final InMemoryBankDataStore store;
    private final TransactionRepository transactionRepository;

    public TransactionProcessor(@NonNull InMemoryBankDataStore store, @NonNull TransactionRepository transactionRepository) {
        this.store = store;
        this.transactionRepository = transactionRepository;
    }

    public Result transfer(@NonNull String fromAccountId, @NonNull String toAccountId, @NonNull Money amount, String note) {
        if (fromAccountId.equals(toAccountId)) return Result.fail("Accounts must be different");
        if (amount.amount().compareTo(BigDecimal.ZERO) <= 0) return Result.fail("Amount must be positive");

        synchronized (store.lock()) {
            Account from = store.getAccount(fromAccountId);
            Account to = store.getAccount(toAccountId);
            if (from == null || to == null) return Result.fail("Account not found");

            Currency cFrom = Currency.getInstance(from.currencyCode);
            Currency cTo = Currency.getInstance(to.currencyCode);
            if (!cFrom.equals(amount.currency()) || !cTo.equals(amount.currency())) return Result.fail("Currency mismatch");

            Money fromBal = store.getBalance(fromAccountId);
            Money toBal = store.getBalance(toAccountId);
            if (fromBal == null || toBal == null) return Result.fail("Balance not available");

            if (fromBal.compareTo(amount) < 0) return Result.fail("Insufficient funds");

            Money newFrom = fromBal.minus(amount);
            Money newTo = toBal.plus(amount);

            store.setBalance(fromAccountId, newFrom);
            store.setBalance(toAccountId, newTo);

            Transaction tx = new Transaction(
                    UUID.randomUUID().toString(),
                    System.currentTimeMillis(),
                    Transaction.Type.TRANSFER,
                    fromAccountId,
                    toAccountId,
                    amount,
                    note
            );
            transactionRepository.add(tx);
            return Result.ok(tx);
        }
    }

    public Result debit(@NonNull String accountId, @NonNull Money amount, String note) {
        if (amount.amount().compareTo(BigDecimal.ZERO) <= 0) return Result.fail("Amount must be positive");

        synchronized (store.lock()) {
            Account acc = store.getAccount(accountId);
            if (acc == null) return Result.fail("Account not found");
            if (!Currency.getInstance(acc.currencyCode).equals(amount.currency())) return Result.fail("Currency mismatch");

            Money bal = store.getBalance(accountId);
            if (bal == null) return Result.fail("Balance not available");
            if (bal.compareTo(amount) < 0) return Result.fail("Insufficient funds");

            Money newBal = bal.minus(amount);
            store.setBalance(accountId, newBal);

            Transaction tx = new Transaction(
                    UUID.randomUUID().toString(),
                    System.currentTimeMillis(),
                    Transaction.Type.DEBIT,
                    accountId,
                    null,
                    amount,
                    note
            );
            transactionRepository.add(tx);
            return Result.ok(tx);
        }
    }

    public Result credit(@NonNull String accountId, @NonNull Money amount, String note) {
        if (amount.amount().compareTo(BigDecimal.ZERO) <= 0) return Result.fail("Amount must be positive");

        synchronized (store.lock()) {
            Account acc = store.getAccount(accountId);
            if (acc == null) return Result.fail("Account not found");
            if (!Currency.getInstance(acc.currencyCode).equals(amount.currency())) return Result.fail("Currency mismatch");

            Money bal = store.getBalance(accountId);
            if (bal == null) return Result.fail("Balance not available");

            Money newBal = bal.plus(amount);
            store.setBalance(accountId, newBal);

            Transaction tx = new Transaction(
                    UUID.randomUUID().toString(),
                    System.currentTimeMillis(),
                    Transaction.Type.CREDIT,
                    null,
                    accountId,
                    amount,
                    note
            );
            transactionRepository.add(tx);
            return Result.ok(tx);
        }
    }
}

package com.example.bankapp;

import android.os.Handler;
import android.os.Looper;

import androidx.annotation.NonNull;
import androidx.lifecycle.LiveData;
import androidx.lifecycle.MutableLiveData;
import androidx.lifecycle.ViewModel;

import java.util.List;

public final class BankingViewModel extends ViewModel {
    public static final class UiState {
        public final List<Account> accounts;
        public final String selectedAccountId;
        public final Money selectedBalance;
        public final String lastMessage;

        UiState(List<Account> accounts, String selectedAccountId, Money selectedBalance, String lastMessage) {
            this.accounts = accounts;
            this.selectedAccountId = selectedAccountId;
            this.selectedBalance = selectedBalance;
            this.lastMessage = lastMessage;
        }
    }

    private final MutableLiveData<UiState> state = new MutableLiveData<>();
    private final Handler main = new Handler(Looper.getMainLooper());

    private final AccountRepository accountRepo;
    private final TransactionProcessor processor;

    public BankingViewModel() {
        InMemoryBankDataStore store = new InMemoryBankDataStore();
        accountRepo = new AccountRepository(store);
        TransactionRepository txRepo = new TransactionRepository(store);
        processor = new TransactionProcessor(store, txRepo);

        List<Account> accounts = accountRepo.listAccounts();
        String selected = accounts.isEmpty() ? null : accounts.get(0).accountId;
        Money bal = selected == null ? null : accountRepo.getBalance(selected);
        state.setValue(new UiState(accounts, selected, bal, null));
    }

    public LiveData<UiState> state() {
        return state;
    }

    public void selectAccount(String accountId) {
        UiState cur = state.getValue();
        if (cur == null) return;
        Money bal = accountRepo.getBalance(accountId);
        state.setValue(new UiState(cur.accounts, accountId, bal, cur.lastMessage));
    }

    public void transfer(@NonNull String toAccountId, @NonNull Money amount, String note) {
        UiState cur = state.getValue();
        if (cur == null || cur.selectedAccountId == null) return;

        new Thread(() -> {
            TransactionProcessor.Result r = processor.transfer(cur.selectedAccountId, toAccountId, amount, note);
            main.post(() -> {
                UiState now = state.getValue();
                if (now == null) return;
                Money bal = now.selectedAccountId == null ? null : accountRepo.getBalance(now.selectedAccountId);
                state.setValue(new UiState(now.accounts, now.selectedAccountId, bal, r.success ? "Transfer complete" : r.message));
            });
        }).start();
    }

    public void credit(@NonNull Money amount, String note) {
        UiState cur = state.getValue();
        if (cur == null || cur.selectedAccountId == null) return;

        new Thread(() -> {
            TransactionProcessor.Result r = processor.credit(cur.selectedAccountId, amount, note);
            main.post(() -> {
                UiState now = state.getValue();
                if (now == null) return;
                Money bal = now.selectedAccountId == null ? null : accountRepo.getBalance(now.selectedAccountId);
                state.setValue(new UiState(now.accounts, now.selectedAccountId, bal, r.success ? "Credit complete" : r.message));
            });
        }).start();
    }

    public void debit(@NonNull Money amount, String note) {
        UiState cur = state.getValue();
        if (cur == null || cur.selectedAccountId == null) return;

        new Thread(() -> {
            TransactionProcessor.Result r = processor.debit(cur.selectedAccountId, amount, note);
            main.post(() -> {
                UiState now = state.getValue();
                if (now == null) return;
                Money bal = now.selectedAccountId == null ? null : accountRepo.getBalance(now.selectedAccountId);
                state.setValue(new UiState(now.accounts, now.selectedAccountId, bal, r.success ? "Debit complete" : r.message));
            });
        }).start();
    }
}

package com.example.bankapp;

import android.os.Bundle;
import android.text.InputType;
import android.view.Gravity;
import android.view.View;
import android.widget.ArrayAdapter;
import android.widget.Button;
import android.widget.EditText;
import android.widget.LinearLayout;
import android.widget.Spinner;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;
import androidx.lifecycle.ViewModelProvider;

import java.util.ArrayList;
import java.util.Currency;
import java.util.List;

public final class BankingActivity extends AppCompatActivity {

    private BankingViewModel vm;

    private Spinner accountSpinner;
    private TextView balanceView;
    private Spinner toAccountSpinner;
    private EditText amountInput;
    private Button transferBtn;
    private TextView messageView;

    private final List<Account> accounts = new ArrayList<>();

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        vm = new ViewModelProvider(this).get(BankingViewModel.class);

        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        int pad = (int) (16 * getResources().getDisplayMetrics().density);
        root.setPadding(pad, pad, pad, pad);
        root.setGravity(Gravity.TOP);

        TextView title = new TextView(this);
        title.setText("Banking");
        title.setTextSize(22f);
        root.addView(title);

        accountSpinner = new Spinner(this);
        root.addView(accountSpinner);

        balanceView = new TextView(this);
        balanceView.setTextSize(18f);
        root.addView(balanceView);

        View divider = new View(this);
        LinearLayout.LayoutParams dlp = new LinearLayout.LayoutParams(LinearLayout.LayoutParams.MATCH_PARENT, (int) (1 * getResources().getDisplayMetrics().density));
        dlp.topMargin = pad;
        dlp.bottomMargin = pad;
        divider.setLayoutParams(dlp);
        divider.setBackgroundColor(0xFFCCCCCC);
        root.addView(divider);

        TextView transferLabel = new TextView(this);
        transferLabel.setText("Transfer");
        transferLabel.setTextSize(18f);
        root.addView(transferLabel);

        toAccountSpinner = new Spinner(this);
        root.addView(toAccountSpinner);

        amountInput = new EditText(this);
        amountInput.setHint("Amount (e.g., 10.00)");
        amountInput.setInputType(InputType.TYPE_CLASS_NUMBER | InputType.TYPE_NUMBER_FLAG_DECIMAL);
        root.addView(amountInput);

        transferBtn = new Button(this);
        transferBtn.setText("Send");
        root.addView(transferBtn);

        messageView = new TextView(this);
        root.addView(messageView);

        setContentView(root);

        vm.state().observe(this, s -> {
            if (s == null) return;

            accounts.clear();
            if (s.accounts != null) accounts.addAll(s.accounts);

            ArrayAdapter<String> adapter = new ArrayAdapter<>(this, android.R.layout.simple_spinner_dropdown_item, names(accounts));
            accountSpinner.setAdapter(adapter);

            int selectedIndex = indexOf(accounts, s.selectedAccountId);
            if (selectedIndex >= 0) accountSpinner.setSelection(selectedIndex);

            ArrayAdapter<String> toAdapter = new ArrayAdapter<>(this, android.R.layout.simple_spinner_dropdown_item, names(accounts));
            toAccountSpinner.setAdapter(toAdapter);

            if (s.selectedBalance != null) {
                balanceView.setText("Balance: " + s.selectedBalance.toString());
            } else {
                balanceView.setText("Balance: -");
            }

            messageView.setText(s.lastMessage == null ? "" : s.lastMessage);
        });

        accountSpinner.setOnItemSelectedListener(new SimpleItemSelectedListener(pos -> {
            if (pos < 0 || pos >= accounts.size()) return;
            vm.selectAccount(accounts.get(pos).accountId);
        }));

        transferBtn.setOnClickListener(v -> {
            int toPos = toAccountSpinner.getSelectedItemPosition();
            int fromPos = accountSpinner.getSelectedItemPosition();
            if (toPos < 0 || toPos >= accounts.size()) return;
            if (fromPos < 0 || fromPos >= accounts.size()) return;

            Account from = accounts.get(fromPos);
            Account to = accounts.get(toPos);

            String amtStr = amountInput.getText() == null ? "" : amountInput.getText().toString().trim();
            if (amtStr.isEmpty()) {
                messageView.setText("Enter an amount");
                return;
            }

            Money amt;
            try {
                amt = new Money(new java.math.BigDecimal(amtStr), Currency.getInstance(from.currencyCode));
            } catch (Exception e) {
                messageView.setText("Invalid amount");
                return;
            }

            vm.transfer(to.accountId, amt, null);
        });
    }

    private static List<String> names(List<Account> accounts) {
        ArrayList<String> out = new ArrayList<>(accounts.size());
        for (Account a : accounts) out.add(a.displayName + " (" + a.accountId + ")");
        return out;
    }

    private static int indexOf(List<Account> accounts, String accountId) {
        if (accountId == null) return -1;
        for (int i = 0; i < accounts.size(); i++) {
            if (accountId.equals(accounts.get(i).accountId)) return i;
        }
        return -1;
    }
}

package com.example.bankapp;

import android.view.View;
import android.widget.AdapterView;

final class SimpleItemSelectedListener implements AdapterView.OnItemSelectedListener {

    interface Callback {
        void onSelected(int position);
    }

    private final Callback callback;

    SimpleItemSelectedListener(Callback callback) {
        this.callback = callback;
    }

    @Override
    public void onItemSelected(AdapterView<?> parent, View view, int position, long id) {
        if (callback != null) callback.onSelected(position);
    }

    @Override
    public void onNothingSelected(AdapterView<?> parent) {
    }
}